import React, { useState, memo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ChevronDown, HelpCircle } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "./src/components/ui/card";

const Section = ({ id, children, className = "" }) => (
  <section id={id} className={`mx-auto w-full max-w-7xl px-6 md:px-10 ${className}`}>{children}</section>
);

const faqs = [
  {
    question: "Kui kaua võtab autohooldus aega?",
    answer: "Sõltuvalt teenusest 1-4 tundi. Keerukamad tööd võivad võtta kauem. Saadame WhatsAppi teavitusi töö edenemisest."
  },
  {
    question: "Kas teete garantiid oma töödele?",
    answer: "Jah, kõikidele töödele anname 6-kuulise garantii. Varuosadele kehtib tootja garantii."
  },
  {
    question: "Milliseid makseviise aktsepteerite?",
    answer: "Võtame vastu sularaha, pangakaarte, pangalingid ja ettemaksuarved ettevõtetele."
  },
  {
    question: "Kas auto jääb ööseks teie juurde?",
    answer: "Harva, enamasti saavad tööd valmis samal päeval. Vajadusel korraldame auto transportimise."
  },
  {
    question: "Kas teete tööd väljaspool Tallinnat?",
    answer: "Teostame väljasõite Harjumaal ja lähivaldades. Hind sõltub kaugusest ja töö keerukusest."
  },
  {
    question: "Milliseid varuosasid kasutate?",
    answer: "Kasutame ainult OE kvaliteediga ja premium varuosasid. Kõik osad on sertifitseeritud."
  },
  {
    question: "Kuidas broneerida aeg?",
    answer: "Kõige kiirem on helistada või kirjutada WhatsAppi. Võimalik ka emaili teel."
  },
  {
    question: "Kas teete kiirtöid?",
    answer: "Jah, kiirtöid teeme prioriteetselt. Helistage ja küsige saadavust."
  }
];

const FaqSection = memo(() => {
  const [openIndex, setOpenIndex] = useState(0);

  const toggleFaq = (index) => {
    setOpenIndex(openIndex === index ? -1 : index);
  };

  return (
    <Section id="faq" className="py-16">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        whileInView={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6 }}
        viewport={{ once: true }}
        className="text-center mb-12"
      >
        <Card className="mx-auto max-w-4xl rounded-3xl border-white/40 bg-white/80 shadow-xl backdrop-blur dark:bg-slate-900/70 dark:border-slate-800">
          <CardHeader>
            <div className="flex items-center justify-center gap-3 mb-4">
              <HelpCircle className="w-8 h-8 text-[#0FB5AF]" />
              <CardTitle className="text-3xl md:text-4xl font-bold tracking-tight text-slate-900 dark:text-slate-100">
                Korduma kippuvad küsimused
              </CardTitle>
            </div>
            <p className="text-slate-800 dark:text-slate-300">
              Leidke vastused enim küsitavatele küsimustele meie teenuste kohta
            </p>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {faqs.map((faq, index) => (
                <div key={index} className="border border-white/40 rounded-2xl overflow-hidden bg-white/50 dark:bg-slate-800/50 backdrop-blur-sm">
                  <button
                    onClick={() => toggleFaq(index)}
                    className="w-full text-left p-6 font-semibold flex justify-between items-center hover:bg-white/60 dark:hover:bg-slate-700/60 transition-colors focus:outline-none focus:ring-2 focus:ring-[#0FB5AF] rounded-2xl"
                    aria-expanded={openIndex === index}
                    aria-controls={`faq-content-${index}`}
                  >
                    <span className="text-slate-900 dark:text-slate-100 pr-4">
                      {faq.question}
                    </span>
                    <motion.div
                      animate={{ rotate: openIndex === index ? 180 : 0 }}
                      transition={{ duration: 0.3 }}
                      className="flex-shrink-0"
                    >
                      <ChevronDown className="w-5 h-5 text-[#0FB5AF]" />
                    </motion.div>
                  </button>
                  <AnimatePresence>
                    {openIndex === index && (
                      <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        transition={{ duration: 0.3, ease: "easeInOut" }}
                        className="overflow-hidden"
                        id={`faq-content-${index}`}
                      >
                        <div className="p-6 border-t border-white/20 bg-slate-50/50 dark:bg-slate-800/30">
                          <p className="text-slate-700 dark:text-slate-300 leading-relaxed">
                            {faq.answer}
                          </p>
                        </div>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      </motion.div>
    </Section>
  );
});

FaqSection.displayName = 'FaqSection';

export default FaqSection;
